export default Navbar;

import React, { useState } from 'react';
import { ScheduleEvent, MinistryType } from '../types';

interface ScheduleProps {
  events: ScheduleEvent[];
}

const Schedule: React.FC<ScheduleProps> = ({ events }) => {
  const [selectedDate, setSelectedDate] = useState<string | null>(events[0]?.date || null);

  const filteredEvents = selectedDate 
    ? events.filter(e => e.date === selectedDate)
    : events;

  // Group events by date for the filter bar
  const uniqueDates = Array.from(new Set(events.map(e => e.date))).sort();

  const formatDate = (dateStr: string) => {
    const options: Intl.DateTimeFormatOptions = { weekday: 'long', day: 'numeric', month: 'short' };
    return new Date(dateStr + 'T00:00:00').toLocaleDateString('es-ES', options);
  };

  return (
    <div className="animate-fade-in space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Programación</h2>
        <div className="flex space-x-2 bg-slate-100 p-1 rounded-xl overflow-x-auto max-w-full">
          {uniqueDates.map(date => (
            <button
              key={date}
              onClick={() => setSelectedDate(date)}
              className={`px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-all ${
                selectedDate === date 
                  ? 'bg-white text-indigo-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              {formatDate(date)}
            </button>
          ))}
        </div>
      </div>

      <div className="space-y-6">
        {filteredEvents.map(event => (
          <div key={event.id} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
              <div>
                <h3 className="font-bold text-lg text-slate-900">{event.title}</h3>
                <p className="text-slate-500 text-sm flex items-center">
                  <i className="far fa-clock mr-2"></i> {event.time}
                </p>
              </div>
              <span className="px-3 py-1 bg-green-100 text-green-700 text-xs font-bold uppercase rounded-full tracking-wider">
                Confirmado
              </span>
            </div>
            <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {(Object.keys(event.ministries) as MinistryType[]).map(min => (
                <div key={min} className="space-y-3">
                  <h4 className="font-bold text-indigo-600 text-sm uppercase tracking-widest border-b border-indigo-100 pb-1">
                    {min}
                  </h4>
                  <div className="space-y-2">
                    {event.ministries[min]?.map((assignment, idx) => (
                      <div key={idx} className="flex justify-between items-center group">
                        <span className="text-slate-500 text-sm">{assignment.position}</span>
                        <span className="font-medium text-slate-800 text-sm group-hover:text-indigo-600 transition-colors">
                          {assignment.personName}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Schedule;

