import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Profile from './components/Profile';
import Schedule from './components/Schedule';
import { MockData } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('schedule');
  const [data, setData] = useState<MockData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Standard fetch is more reliable for local data.json in browser-based ESM
    fetch('./data.json')
      .then((res) => {
        if (!res.ok) {
          throw new Error(`Error HTTP: ${res.status}`);
        }
        return res.json();
      })
      .then((jsonData) => {
        setData(jsonData as MockData);
        setLoading(false);
      })
      .catch((err) => {
        console.error("Error loading mock data", err);
        setError("No se pudo cargar la información. Por favor, intenta de nuevo más tarde.");
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="text-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-slate-500 font-medium">Cargando Ecclesia Flow...</p>
        </div>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4">
        <div className="max-w-md w-full bg-white p-8 rounded-2xl shadow-sm border border-slate-200 text-center">
          <i className="fas fa-exclamation-triangle text-red-500 text-4xl mb-4"></i>
          <h2 className="text-xl font-bold text-slate-800 mb-2">¡Ups! Algo salió mal</h2>
          <p className="text-slate-600 mb-6">{error || "No hay datos disponibles."}</p>
          <button 
            onClick={() => window.location.reload()}
            className="w-full py-3 bg-indigo-600 text-white rounded-xl font-semibold hover:bg-indigo-700 transition-colors"
          >
            Reintentar
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="max-w-5xl mx-auto px-4 py-8">
        {activeTab === 'profile' && <Profile user={data.user} />}
        {activeTab === 'schedule' && <Schedule events={data.events} />}
        {activeTab === 'announcements' && (
          <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-300">
             <i className="fas fa-bullhorn text-4xl text-slate-300 mb-4"></i>
             <h2 className="text-xl font-semibold text-slate-800">No hay anuncios nuevos</h2>
             <p className="text-slate-500">Vuelve pronto para ver las últimas noticias de la congregación.</p>
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-slate-200 py-10">
        <div className="max-w-5xl mx-auto px-4 text-center">
          <p className="text-slate-400 text-sm">© 2024 Ecclesia Flow - Gestión Eclesiástica Digital</p>
          <div className="mt-4 flex justify-center space-x-6 text-slate-400">
            <a href="#" className="hover:text-indigo-600"><i className="fab fa-facebook"></i></a>
            <a href="#" className="hover:text-indigo-600"><i className="fab fa-instagram"></i></a>
            <a href="#" className="hover:text-indigo-600"><i className="fab fa-youtube"></i></a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

