import React, { useState, useRef, useEffect } from 'react';

const Navbar = ({ activeTab, setActiveTab }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [showTcdSubmenu, setShowTcdSubmenu] = useState(false);
  const submenuRef = useRef(null);

  const tabs = [
    { id: 'schedule', label: 'Programación', icon: 'fa-calendar-alt' },
    { id: 'ministries', label: 'Ministerios', icon: 'fa-sitemap' },
    { id: 'users', label: 'Usuarios', icon: 'fa-users' },
    { 
      id: 'tcd-root', 
      label: 'TCD', 
      icon: 'fa-book-open',
      hasSubmenu: true,
      submenu: [
        { id: 'tcd', label: 'Mi TCD', icon: 'fa-upload' },
        { id: 'reports', label: 'Reportes TCD', icon: 'fa-chart-bar' }
      ]
    },
    { id: 'profile', label: 'Mi Perfil', icon: 'fa-user' }
  ];

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (submenuRef.current && !submenuRef.current.contains(event.target)) {
        setShowTcdSubmenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleTabClick = (id) => {
    setActiveTab(id);
    setIsOpen(false);
    setShowTcdSubmenu(false);
  };

  return (
    <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
      <div className="max-w-6xl mx-auto px-4">
        <div className="flex justify-between items-center h-16">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
              <i className="fas fa-church text-sm"></i>
            </div>
            <span className="font-bold text-lg tracking-tight text-slate-800">
              Ecclesia<span className="text-indigo-600">Flow</span>
            </span>
          </div>

          <div className="hidden md:flex space-x-4 h-full">
            {tabs.map(tab => (
              <div key={tab.id} className="relative flex items-center h-full" ref={tab.hasSubmenu ? submenuRef : null}>
                <button
                  onClick={() => {
                    if (tab.hasSubmenu) {
                      setShowTcdSubmenu(!showTcdSubmenu);
                    } else {
                      handleTabClick(tab.id);
                    }
                  }}
                  className={`flex items-center space-x-2 px-3 h-full border-b-2 font-medium text-sm transition-colors ${
                    (activeTab === tab.id || (tab.hasSubmenu && (activeTab === 'tcd' || activeTab === 'reports')))
                      ? 'border-indigo-600 text-indigo-600' 
                      : 'border-transparent text-slate-500 hover:text-indigo-500'
                  }`}
                >
                  <i className={`fas ${tab.icon}`}></i>
                  <span>{tab.label}</span>
                  {tab.hasSubmenu && <i className={`fas fa-chevron-down text-[10px] ml-1 transition-transform ${showTcdSubmenu ? 'rotate-180' : ''}`}></i>}
                </button>

                {tab.hasSubmenu && showTcdSubmenu && (
                  <div className="absolute top-full left-0 w-48 bg-white border border-slate-200 shadow-xl rounded-b-xl py-2 animate-in fade-in slide-in-from-top-2 duration-200">
                    {tab.submenu.map(sub => (
                      <button
                        key={sub.id}
                        onClick={() => handleTabClick(sub.id)}
                        className={`w-full text-left px-4 py-2 text-sm flex items-center space-x-3 hover:bg-slate-50 transition-colors ${
                          activeTab === sub.id ? 'text-indigo-600 font-bold bg-indigo-50/50' : 'text-slate-600'
                        }`}
                      >
                        <i className={`fas ${sub.icon} w-4 text-center`}></i>
                        <span>{sub.label}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </div>

          <div className="md:hidden flex items-center">
            <button onClick={() => setIsOpen(!isOpen)} className="text-slate-500 p-2">
              <i className={`fas ${isOpen ? 'fa-times' : 'fa-bars'} text-xl`}></i>
            </button>
          </div>
        </div>
      </div>

      <div className={`fixed top-0 right-0 h-full w-64 bg-white z-50 shadow-xl transform transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'} md:hidden`}>
        <div className="p-6 flex flex-col h-full overflow-y-auto">
          <div className="flex justify-between items-center mb-8">
            <span className="font-bold text-lg text-slate-800">Menú Principal</span>
            <button onClick={() => setIsOpen(false)} className="text-slate-400 p-1">
              <i className="fas fa-times text-xl"></i>
            </button>
          </div>
          <div className="flex flex-col space-y-2">
            {tabs.map(tab => (
              <div key={tab.id} className="flex flex-col">
                <button
                  onClick={() => { if (!tab.hasSubmenu) handleTabClick(tab.id); }}
                  className={`flex items-center space-x-4 px-4 py-3 rounded-xl font-medium text-sm transition-all ${
                    (activeTab === tab.id && !tab.hasSubmenu) ? 'bg-indigo-50 text-indigo-600' : 'text-slate-500'
                  }`}
                >
                  <i className={`fas ${tab.icon} w-5`}></i>
                  <span>{tab.label}</span>
                </button>
                {tab.hasSubmenu && (
                  <div className="ml-9 flex flex-col space-y-1 border-l-2 border-slate-100 pl-4 mt-1">
                    {tab.submenu.map(sub => (
                      <button key={sub.id} onClick={() => handleTabClick(sub.id)} className={`text-left py-2 text-sm ${activeTab === sub.id ? 'text-indigo-600 font-bold' : 'text-slate-500'}`}>
                        {sub.label}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar.jsx';
import Profile from './components/Profile.jsx';
import Schedule from './components/Schedule.jsx';
import UsersManager from './components/UsersManager.jsx';
import TCDManager from './components/TCDManager.jsx';
import Reports from './components/Reports.jsx';
import MinistryManager from './components/MinistryManager.jsx';

const App = () => {
  const [activeTab, setActiveTab] = useState('schedule');
  const [data, setData] = useState(null);
  const [users, setUsers] = useState([]);
  const [tcdEntries, setTcdEntries] = useState([]);
  const [ministries, setMinistries] = useState([
    { id: 'm1', name: 'Alabanza', positions: ['Guitarra', 'Bajo', 'Batería', 'Piano', 'Voz'] },
    { id: 'm2', name: 'Audiovisuales', positions: ['Cámara', 'Computador Letras', 'Consola Sonido'] }
  ]);
  const [assignments, setAssignments] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('./data.json')
      .then((res) => {
        if (!res.ok) throw new Error(`Error HTTP: ${res.status}`);
        return res.json();
      })
      .then((jsonData) => {
        setData(jsonData);
        setUsers(jsonData.mockUsers || [{ ...jsonData.user, active: true }]);

        const mockTcds = [
          { id: 't1', userId: 'u1', userName: 'Juan Pérez', date: '2024-05-18', image: 'https://picsum.photos/seed/bible1/400/300' },
          { id: 't2', userId: 'u1', userName: 'Juan Pérez', date: '2024-05-19', image: 'https://picsum.photos/seed/bible2/400/300' },
          { id: 't3', userId: 'u2', userName: 'Andrés Soto', date: '2024-05-19', image: 'https://picsum.photos/seed/bible3/400/300' }
        ];
        setTcdEntries(mockTcds);
        setLoading(false);
      })
      .catch((err) => {
        console.error("Error loading mock data", err);
        setLoading(false);
      });
  }, []);

  const handleAddUser = (newUser) => {
    setUsers([...users, { ...newUser, id: Date.now().toString(), active: true }]);
  };

  const toggleUserStatus = (id) => {
    setUsers(users.map(u => u.id === id ? { ...u, active: !u.active } : u));
  };

  const addTcdEntry = (entry) => {
    setTcdEntries([...tcdEntries, { ...entry, id: Date.now().toString() }]);
  };

  const handleAddMinistry = (name, positions) => {
    setMinistries([...ministries, { id: Date.now().toString(), name, positions }]);
  };

  const handleAssignPerson = (assignment) => {
    setAssignments([...assignments, { ...assignment, id: Date.now().toString() }]);
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-slate-50"><div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div></div>;

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="max-w-6xl mx-auto px-4 py-8">
        {data && activeTab === 'profile' && <Profile user={data.user} />}
        {data && activeTab === 'schedule' && <Schedule events={data.events} />}
        {activeTab === 'users' && (
          <UsersManager users={users} onAddUser={handleAddUser} onToggleStatus={toggleUserStatus} />
        )}
        {activeTab === 'tcd' && (
          <TCDManager tcdEntries={tcdEntries} onAddEntry={addTcdEntry} currentUser={data?.user} />
        )}
        {activeTab === 'reports' && (
          <Reports users={users} tcdEntries={tcdEntries} />
        )}
        {activeTab === 'ministries' && (
          <MinistryManager 
            ministries={ministries} 
            users={users} 
            assignments={assignments}
            onAddMinistry={handleAddMinistry} 
            onAssignPerson={handleAssignPerson}
          />
        )}
      </main>
      <footer className="mt-20 border-t border-slate-200 py-10 text-center text-slate-400 text-sm">
        <p>© 2024 Ecclesia Flow - Gestión Eclesiástica Digital</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';

const MinistryManager = ({ ministries, users, assignments, onAddMinistry, onAssignPerson }) => {
  const [view, setView] = useState('list'); // 'list' | 'add-ministry' | 'assign'
  const [newMin, setNewMin] = useState({ name: '', positions: '' });
  const [newAssign, setNewAssign] = useState({ userId: '', ministryId: '', position: '' });

  const handleCreateMinistry = (e) => {
    e.preventDefault();
    const posArray = newMin.positions.split(',').map(p => p.trim()).filter(p => p !== '');
    onAddMinistry(newMin.name, posArray);
    setNewMin({ name: '', positions: '' });
    setView('list');
  };

  const handleAssignSubmit = (e) => {
    e.preventDefault();
    const user = users.find(u => u.id === newAssign.userId);
    const ministry = ministries.find(m => m.id === newAssign.ministryId);
    onAssignPerson({
      ...newAssign,
      userName: user?.name,
      ministryName: ministry?.name
    });
    setNewAssign({ userId: '', ministryId: '', position: '' });
    setView('list');
  };

  const selectedMinistry = ministries.find(m => m.id === newAssign.ministryId);

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Gestión de Ministerios</h2>
        <div className="flex gap-2">
          <button 
            onClick={() => setView('add-ministry')}
            className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all ${view === 'add-ministry' ? 'bg-indigo-600 text-white' : 'bg-white border text-slate-600 hover:bg-slate-50'}`}
          >
            <i className="fas fa-plus mr-2"></i>Nuevo Ministerio
          </button>
          <button 
            onClick={() => setView('assign')}
            className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all ${view === 'assign' ? 'bg-indigo-600 text-white' : 'bg-white border text-slate-600 hover:bg-slate-50'}`}
          >
            <i className="fas fa-user-plus mr-2"></i>Asignar Persona
          </button>
          <button 
            onClick={() => setView('list')}
            className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all ${view === 'list' ? 'bg-indigo-600 text-white' : 'bg-white border text-slate-600 hover:bg-slate-50'}`}
          >
            <i className="fas fa-list mr-2"></i>Ver Todo
          </button>
        </div>
      </div>

      {view === 'add-ministry' && (
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm animate-in fade-in zoom-in duration-200">
          <h3 className="text-lg font-bold mb-4 text-slate-700">Crear Estructura de Ministerio</h3>
          <form onSubmit={handleCreateMinistry} className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nombre del Ministerio</label>
              <input 
                type="text" placeholder="Ej: Alabanza y Adoración" required
                className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                value={newMin.name} onChange={e => setNewMin({...newMin, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Posiciones (separadas por comas)</label>
              <textarea 
                placeholder="Ej: Piano, Bajo, Voz, Guitarra" required
                className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none h-24"
                value={newMin.positions} onChange={e => setNewMin({...newMin, positions: e.target.value})}
              />
              <p className="text-[10px] text-slate-400 mt-1 italic">* Estas posiciones estarán disponibles para asignar servidores luego.</p>
            </div>
            <button className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100">
              Guardar Ministerio
            </button>
          </form>
        </div>
      )}

      {view === 'assign' && (
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm animate-in fade-in zoom-in duration-200">
          <h3 className="text-lg font-bold mb-4 text-slate-700">Asignar Persona a Posición</h3>
          <form onSubmit={handleAssignSubmit} className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Seleccionar Usuario</label>
                <select 
                  className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                  value={newAssign.userId} onChange={e => setNewAssign({...newAssign, userId: e.target.value})} required
