import React, { useState, useMemo } from 'react';

const Schedule = ({ events }) => {
  // Obtener fecha actual y fecha límite (hoy + 5 días)
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const limitDate = new Date(today);
  limitDate.setDate(today.getDate() + 5);

  // Filtrar eventos que estén entre hoy y los próximos 5 días
  const upcomingEvents = useMemo(() => {
    return events.filter(event => {
      const eventDate = new Date(event.date + 'T00:00:00');
      return eventDate >= today && eventDate <= limitDate;
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [events]);

  const uniqueDates = useMemo(() => {
    return Array.from(new Set(upcomingEvents.map(e => e.date))).sort();
  }, [upcomingEvents]);

  const [selectedDate, setSelectedDate] = useState(uniqueDates[0] || null);

  // Si la fecha seleccionada ya no está en los eventos filtrados (por cambios externos), resetearla
  if (selectedDate && !uniqueDates.includes(selectedDate)) {
    setSelectedDate(uniqueDates[0] || null);
  }

  const filteredEvents = selectedDate 
    ? upcomingEvents.filter(e => e.date === selectedDate)
    : upcomingEvents;

  const formatDate = (dateStr) => {
    return new Date(dateStr + 'T00:00:00').toLocaleDateString('es-ES', { 
      weekday: 'short', 
      day: 'numeric',
      month: 'short'
    });
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Programación Próximos 5 Días</h2>
          <p className="text-sm text-slate-500">
            {today.toLocaleDateString('es-ES')} al {limitDate.toLocaleDateString('es-ES')}
          </p>
        </div>

        {uniqueDates.length > 0 && (
          <div className="flex space-x-2 bg-slate-100 p-1 rounded-xl self-start">
            <button
              onClick={() => setSelectedDate(null)}
              className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
                selectedDate === null ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-indigo-400'
              }`}
            >
              Ver Todos
            </button>
            {uniqueDates.map(date => (
              <button
                key={date}
                onClick={() => setSelectedDate(date)}
                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
                  selectedDate === date ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-indigo-400'
                }`}
              >
                {formatDate(date)}
              </button>
            ))}
          </div>
        )}
      </div>

      {upcomingEvents.length === 0 ? (
        <div className="bg-white rounded-3xl border border-dashed border-slate-300 p-16 text-center animate-in fade-in zoom-in duration-300">
          <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
            <i className="fas fa-calendar-times text-slate-300 text-4xl"></i>
          </div>
          <h3 className="text-xl font-bold text-slate-700 mb-2">No existe programación</h3>
          <p className="text-slate-500 max-w-xs mx-auto">
            No hay actividades programadas para los próximos 5 días. Por favor, consulta más tarde o contacta con tu líder.
          </p>
        </div>
      ) : (
        <div className="grid gap-6">
          {filteredEvents.map(event => (
            <div key={event.id} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden hover:border-indigo-200 transition-colors animate-in slide-in-from-bottom-4 duration-500">
              <div className="bg-slate-50/50 px-6 py-4 border-b flex justify-between items-center">
                <div>
                  <div className="flex items-center gap-2 mb-1">
                    <span className="bg-indigo-100 text-indigo-700 text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider">
                      {formatDate(event.date)}
                    </span>
                    <span className="text-slate-400 text-xs">•</span>
                    <span className="text-slate-500 text-xs font-medium">{event.time}</span>
                  </div>
                  <h3 className="font-bold text-lg text-slate-800">{event.title}</h3>
                </div>
                <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center border border-slate-100 shadow-sm">
                  <i className="fas fa-church text-indigo-400"></i>
                </div>
              </div>
              <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {Object.keys(event.ministries).map(min => (
                  <div key={min} className="space-y-3">
                    <h4 className="font-bold text-indigo-600 text-[10px] uppercase tracking-[0.2em] border-b border-slate-100 pb-2">{min}</h4>
                    <div className="space-y-3">
                      {event.ministries[min].map((asgn, idx) => (
                        <div key={idx} className="group">
                          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mb-0.5">{asgn.position}</div>
                          <div className="flex items-center gap-2">
                            <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full"></div>
                            <span className="font-semibold text-sm text-slate-700 group-hover:text-indigo-600 transition-colors">
                              {asgn.personName}
                            </span>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Schedule;

import React, { useState } from 'react';

const MinistryManager = ({ ministries, users, assignments, onAddMinistry, onAssignPerson, onAddEvent }) => {
  const [view, setView] = useState('list'); // 'list' | 'add-ministry' | 'assign' | 'create-schedule'
  const [newMin, setNewMin] = useState({ name: '', positions: '' });
  const [newAssign, setNewAssign] = useState({ userId: '', ministryId: '', position: '' });

  // Estado para la creación de nueva programación
  const [newEvent, setNewEvent] = useState({
    title: '',
    date: '',
    time: '09:00 AM',
    ministries: {}
  });

  const handleCreateMinistry = (e) => {
    e.preventDefault();
    const posArray = newMin.positions.split(',').map(p => p.trim()).filter(p => p !== '');
    onAddMinistry(newMin.name, posArray);
    setNewMin({ name: '', positions: '' });
    setView('list');
  };

  const handleAssignSubmit = (e) => {
    e.preventDefault();
    const user = users.find(u => u.id === newAssign.userId);
    const ministry = ministries.find(m => m.id === newAssign.ministryId);
    onAssignPerson({
      ...newAssign,
      userName: user?.name,
      ministryName: ministry?.name
    });
    setNewAssign({ userId: '', ministryId: '', position: '' });
    setView('list');
  };

  const handleAddPersonToEvent = (minName, position, personName) => {
    const updatedMinistries = { ...newEvent.ministries };
    if (!updatedMinistries[minName]) updatedMinistries[minName] = [];

    // Evitar duplicados en la misma posición
    const existingIndex = updatedMinistries[minName].findIndex(p => p.position === position);
    if (existingIndex > -1) {
      updatedMinistries[minName][existingIndex].personName = personName;
    } else {
      updatedMinistries[minName].push({ position, personName });
    }

    setNewEvent({ ...newEvent, ministries: updatedMinistries });
  };

  const handleSaveEvent = () => {
    if (!newEvent.title || !newEvent.date || Object.keys(newEvent.ministries).length === 0) {
      alert("Por favor completa el título, fecha y al menos una asignación.");
      return;
    }
    onAddEvent({ ...newEvent, id: Date.now().toString() });
    setNewEvent({ title: '', date: '', time: '09:00 AM', ministries: {} });
    setView('list');
    alert("Programación guardada exitosamente");
  };

  const selectedMinistry = ministries.find(m => m.id === newAssign.ministryId);

